import React from 'react';
import '../../css/roundedTextBox.css';


const Input_with_image = ({ icon, alt, type = 'text', placeholder, value, onChange }) => {
  return (
    <div className="input_block">
      <div>
        <img src={icon} alt={alt} />
      </div>
      <div>
        <input
          type={type}
          placeholder={placeholder}
          value={value}
          onChange={onChange}
        />
      </div>
    </div>
  );
};

export default Input_with_image;
